using System.Text.Json.Serialization;
using Newtonsoft.Json;

namespace RepairPlanner.Models;

/// <summary>
/// Represents a work order generated by the Repair Planner Agent.
/// This is the primary output saved to Cosmos DB WorkOrders container.
/// </summary>
public sealed class WorkOrder
{
    [JsonPropertyName("id")]
    [JsonProperty("id")]
    public string Id { get; set; } = Guid.NewGuid().ToString();

    [JsonPropertyName("workOrderNumber")]
    [JsonProperty("workOrderNumber")]
    public string WorkOrderNumber { get; set; } = string.Empty;

    [JsonPropertyName("machineId")]
    [JsonProperty("machineId")]
    public string MachineId { get; set; } = string.Empty;

    [JsonPropertyName("machineName")]
    [JsonProperty("machineName")]
    public string MachineName { get; set; } = string.Empty;

    [JsonPropertyName("title")]
    [JsonProperty("title")]
    public string Title { get; set; } = string.Empty;

    [JsonPropertyName("description")]
    [JsonProperty("description")]
    public string Description { get; set; } = string.Empty;

    [JsonPropertyName("type")]
    [JsonProperty("type")]
    public string Type { get; set; } = "corrective"; // "corrective", "preventive", "emergency"

    [JsonPropertyName("priority")]
    [JsonProperty("priority")]
    public string Priority { get; set; } = "medium"; // "critical", "high", "medium", "low"

    [JsonPropertyName("status")]
    [JsonProperty("status")]
    public string Status { get; set; } = "pending"; // "pending", "scheduled", "in-progress", "completed", "cancelled"

    [JsonPropertyName("assignedTo")]
    [JsonProperty("assignedTo")]
    public string? AssignedTo { get; set; } // Technician ID

    [JsonPropertyName("assignedTechnicianName")]
    [JsonProperty("assignedTechnicianName")]
    public string? AssignedTechnicianName { get; set; }

    [JsonPropertyName("estimatedDuration")]
    [JsonProperty("estimatedDuration")]
    public int EstimatedDuration { get; set; } // Total minutes

    [JsonPropertyName("actualDuration")]
    [JsonProperty("actualDuration")]
    public int? ActualDuration { get; set; }

    [JsonPropertyName("createdAt")]
    [JsonProperty("createdAt")]
    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;

    [JsonPropertyName("scheduledStart")]
    [JsonProperty("scheduledStart")]
    public DateTime? ScheduledStart { get; set; }

    [JsonPropertyName("scheduledEnd")]
    [JsonProperty("scheduledEnd")]
    public DateTime? ScheduledEnd { get; set; }

    [JsonPropertyName("actualStart")]
    [JsonProperty("actualStart")]
    public DateTime? ActualStart { get; set; }

    [JsonPropertyName("actualEnd")]
    [JsonProperty("actualEnd")]
    public DateTime? ActualEnd { get; set; }

    [JsonPropertyName("faultId")]
    [JsonProperty("faultId")]
    public string? FaultId { get; set; }

    [JsonPropertyName("faultType")]
    [JsonProperty("faultType")]
    public string FaultType { get; set; } = string.Empty;

    [JsonPropertyName("tasks")]
    [JsonProperty("tasks")]
    public List<RepairTask> Tasks { get; set; } = [];

    [JsonPropertyName("partsUsed")]
    [JsonProperty("partsUsed")]
    public List<WorkOrderPartUsage> PartsUsed { get; set; } = [];

    [JsonPropertyName("notes")]
    [JsonProperty("notes")]
    public string Notes { get; set; } = string.Empty;

    [JsonPropertyName("estimatedCost")]
    [JsonProperty("estimatedCost")]
    public decimal EstimatedCost { get; set; }

    [JsonPropertyName("actualCost")]
    [JsonProperty("actualCost")]
    public decimal? ActualCost { get; set; }
}
